import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as d,e as c}from"./app-be253e4c.js";const o={},s=c(`<h1 id="diffstat命令" tabindex="-1"><a class="header-anchor" href="#diffstat命令" aria-hidden="true">#</a> diffstat命令</h1><p><code>diffstat</code>命令根据<code>diff</code>的比较结果，统计各文件的插入、删除、修改等差异计量。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>diffstat <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>files<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-c</code>: 输出的每一行都以<code>＃</code>作为前缀，使其成为<code>Shell</code>脚本的注释行。</li><li><code>-C</code>: 添加<code>SGR</code>颜色转义序列以突出显示直方图。</li><li><code>-e</code>: 将标准错误重定向到<code>file</code>。</li><li><code>-f &lt;num&gt;</code>: 指定直方图的格式，<code>0</code>仅显示插入<code>+</code>，删除<code>-</code>或修改<code>!</code>的值和单个直方图代码，<code>1</code>正常输出，<code>2</code>用点填充直方图，<code>4</code>用直方图打印每个值，任何非零值都会给出直方图，点和单个值可以组合。</li><li><code>-H</code>: 打印使用情况消息并退出。</li><li><code>-k</code>: 禁止合并报告中的文件名。</li><li><code>-l</code>: 仅列出文件名，不生成直方图。</li><li><code>-n &lt;file length&gt;</code>: 指定文件名长度，指定的长度必须大于或等于所有文件中最长的文件名。</li><li><code>-o &lt;file&gt;</code>: 将标准输出重定向到<code>file</code>。</li><li><code>-p &lt;file length&gt;</code>: 与<code>-n</code>参数相同，但此处的<code>&lt;file length&gt;</code>包括了文件的路径。</li><li><code>-r</code>: 提供对直方图所示数据的可选舍入，而不是通过误差调整来截断，<code>0</code>是默认值，不进行舍入，但累积的错误将添加到以下列，<code>1</code>舍入数据，<code>2</code>对数据进行舍入并调整直方图，以确保即使有差异通常会四舍五入也存在差异。</li><li><code>-t</code>: 覆盖直方图，生成逗号分隔值的输出。</li><li><code>-u</code>: 禁止在报告中对文件名进行排序。</li><li><code>-v</code>: 显示进度，例如如果将输出重定向到文件，则将进度消息写入标准错误。</li><li><code>-w</code>: 指定输出时栏位的宽度。</li><li><code>-V</code>: 显示版本信息。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>统计<code>diff</code>的比较结果的差异信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">diff</span> file.txt file2.txt <span class="token operator">|</span> diffstat <span class="token parameter variable">-v</span>
</code></pre></div><p>统计<code>diff</code>的比较结果的差异信息，仅列出文件名，不生成直方图。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">diff</span> file.txt file2.txt <span class="token operator">|</span> diffstat <span class="token parameter variable">-l</span>
</code></pre></div><p>统计<code>diff</code>的比较结果的差异信息，指定直方图的最大宽度。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">diff</span> file.txt file2.txt <span class="token operator">|</span> diffstat <span class="token parameter variable">-w</span> <span class="token number">11</span>
</code></pre></div>`,13),t=[s];function i(l,n){return a(),d("div",null,t)}const r=e(o,[["render",i],["__file","diffstat.html.vue"]]);export{r as default};
